const token = $env.LINE_ACCESS_TOKEN;
const blockFlag = $env.N8N_BLOCK_ENV_ACCESS_IN_NODE;
return [{ json: {
  LINE_ACCESS_TOKEN: token ? 'OK len=' + token.length : 'MISSING',
  N8N_BLOCK_ENV_ACCESS_IN_NODE: blockFlag || 'NOT SET',
  status: (token && blockFlag === 'false') ? 'READY' : 'NEEDS_FIX',
  hint: !token
    ? 'env LINE_ACCESS_TOKEN ไม่มีค่า — ลืมตั้งหรือยังไม่ deploy'
    : blockFlag !== 'false'
    ? 'env N8N_BLOCK_ENV_ACCESS_IN_NODE ต้องเป็น false (string) — ตอนนี้เป็น: ' + blockFlag
    : 'พร้อมใช้ — LINE token เข้าถึงได้จาก expression แล้ว'
}}];
